class Solution:
    def countLargestGroup(self, n: int) -> int:
        groups = {}
        for i in range(1, n + 1):
            digit_sum = sum(int(digit) for digit in str(i))
            if digit_sum not in groups:
                groups[digit_sum] = 1
            else:
                groups[digit_sum] += 1
        max_group_size = max(groups.values())
        return sum(size == max_group_size for size in groups.values())
